//! # MegaDepth Simulation — Real-world Geometry Stress Test
//!
//! Simulates the ingestion of MegaDepth-style landmark data.
//! Instead of simple logic paths, we generate a complex 3D Voxel Cloud
//! (representing a cathedral arch or monument) and project it as "shadows".
//!
//! The Sovereign Sieve must then re-materialize the landmark from the views.

use distributed_inference::holographic_reconstruction::{
    ProjectionView, VirtualShutter, VoxelCoord,
};
use distributed_inference::pleromatic_frame::{PleromaticFrame, PleromaticMediaType};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!(" [ MEGADEPTH SIMULATION: LANDMARK RECONSTRUCTION ] ");

    // 1. Generate "Landmark" Voxel Cloud (A Parabolic Arch)
    let mut landmark_voxels = Vec::new();
    for x in 10..30 {
        // Parabola: z = -(x-20)^2 / 2 + 30
        let x_f = x as f32;
        let z = (-(x_f - 20.0).powi(2) / 2.0 + 30.0) as i32;
        for y in 10..15 {
            // Depth of the arch
            landmark_voxels.push(VoxelCoord { x, y, z });
        }
    }
    println!(" Generated Landmark: {} voxels", landmark_voxels.len());

    // 2. Project 3 Views (Shadows)
    let mut views = Vec::new();
    let angles = [0.0, 1.0, 2.0]; // Radians
    let width = 80;
    let height = 40;
    let center = VoxelCoord {
        x: 20,
        y: 12,
        z: 15,
    };

    for (i, &angle) in angles.iter().enumerate() {
        let view_id = format!("megadepth-cam-{}", i);
        let mut frame_data = vec![0u8; width * height];

        let view_stub = ProjectionView {
            view_id: view_id.clone(),
            angle_rad: angle,
            frame_data: Vec::new(),
            width,
            height,
        };

        for &coord in &landmark_voxels {
            let (u, v) = VirtualShutter::project(coord, &view_stub, center);
            if u < width && v < height {
                frame_data[v * width + u] = 255; // "White" pixel where the landmark is
            }
        }

        views.push(ProjectionView {
            view_id,
            angle_rad: angle,
            frame_data,
            width,
            height,
        });
        println!(
            " Projected View {}: {} active pixels",
            i,
            views
                .last()
                .unwrap()
                .frame_data
                .iter()
                .filter(|&&p| p > 0)
                .count()
        );
    }

    // 3. Bundle into Pleromatic Frames
    println!(" [ EMITTING PLEROMATIC FRAMES ] ");
    for (i, view) in views.into_iter().enumerate() {
        // In a real MegaDepth test, frame_data would be the actual image pixels.
        // For the sim, it's the mask of the arch.
        let frame = PleromaticFrame::grounding(
            format!("megadepth-node-{}", i),
            PleromaticMediaType::Image,
            view.frame_data.clone(),
        );

        // We'd send this over the partyline.
        // Here we just verify the manifest fits the state.
        println!(
            " Frame {}: size={} bytes",
            i,
            bincode::serialize(&frame)?.len()
        );
    }

    println!(" [ SUCCESS ] Landmark simulation ready for SovereignSieve validation.");
    Ok(())
}
